import React, { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Zap, Briefcase, BookOpen, ChevronRight } from 'lucide-react';
import toast from 'react-hot-toast';
import { aiAPI } from '../utils/api';
import { useAuth } from '../store/AuthContext';

// ─── Type Selector ────────────────────────────────────────────────────────────
const TypeSelector = ({ onSelect }) => (
  <div className="container" style={{ paddingTop: '60px', paddingBottom: '60px' }}>
    <div className="fade-in" style={{ textAlign: 'center', marginBottom: '48px' }}>
      <h1 style={{ fontSize: '36px', letterSpacing: '-0.03em', marginBottom: '12px' }}>
        What would you like to create?
      </h1>
      <p style={{ color: 'var(--text-secondary)', fontSize: '16px' }}>
        Choose a content type to get started with AI generation
      </p>
    </div>

    <div style={{
      display: 'grid',
      gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
      gap: '20px',
      maxWidth: '680px',
      margin: '0 auto',
    }}>
      {[
        {
          type: 'resume',
          icon: Briefcase,
          title: 'Resume',
          desc: 'Generate a professional, ATS-optimized resume tailored to your target role.',
          color: 'var(--accent)',
          bg: 'rgba(108,99,255,0.1)',
          border: 'rgba(108,99,255,0.3)',
        },
        {
          type: 'blog',
          icon: BookOpen,
          title: 'Blog Post',
          desc: 'Create an engaging, SEO-optimized blog article on any topic.',
          color: 'var(--accent-green)',
          bg: 'rgba(67,217,162,0.08)',
          border: 'rgba(67,217,162,0.25)',
        },
      ].map(({ type, icon: Icon, title, desc, color, bg, border }) => (
        <button
          key={type}
          className="card fade-in"
          onClick={() => onSelect(type)}
          style={{
            cursor: 'pointer',
            textAlign: 'left',
            background: bg,
            border: `1px solid ${border}`,
            transition: 'all var(--transition)',
            display: 'flex',
            flexDirection: 'column',
            gap: '16px',
            padding: '28px',
          }}
          onMouseEnter={e => {
            e.currentTarget.style.transform = 'translateY(-4px)';
            e.currentTarget.style.boxShadow = `0 8px 32px ${border}`;
          }}
          onMouseLeave={e => {
            e.currentTarget.style.transform = 'none';
            e.currentTarget.style.boxShadow = 'none';
          }}
        >
          <div style={{
            width: '52px', height: '52px',
            background: `${color}25`,
            borderRadius: '14px',
            display: 'flex', alignItems: 'center', justifyContent: 'center',
          }}>
            <Icon size={24} color={color} />
          </div>
          <div>
            <h3 style={{ fontSize: '20px', marginBottom: '8px' }}>{title}</h3>
            <p style={{ color: 'var(--text-secondary)', fontSize: '14px', lineHeight: '1.6' }}>{desc}</p>
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: '6px', color, fontSize: '13px', fontWeight: '700', marginTop: 'auto' }}>
            Generate {title} <ChevronRight size={14} />
          </div>
        </button>
      ))}
    </div>
  </div>
);

// ─── Resume Form ──────────────────────────────────────────────────────────────
const ResumeForm = ({ onSubmit, loading }) => {
  const [form, setForm] = useState({
    name: '', jobTitle: '', industry: 'Technology',
    experienceLevel: 'Mid-level', experience: '',
    skills: '', education: '', achievements: '', language: 'English',
  });

  const set = (field) => (e) => setForm(prev => ({ ...prev, [field]: e.target.value }));

  return (
    <form onSubmit={(e) => { e.preventDefault(); onSubmit(form); }}
      style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px' }}>
        <div>
          <label className="label">Full Name *</label>
          <input className="input" placeholder="Jane Smith" value={form.name} onChange={set('name')} required />
        </div>
        <div>
          <label className="label">Target Job Title *</label>
          <input className="input" placeholder="Senior Software Engineer" value={form.jobTitle} onChange={set('jobTitle')} required />
        </div>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px' }}>
        <div>
          <label className="label">Industry</label>
          <select className="input" value={form.industry} onChange={set('industry')} style={{ cursor: 'pointer' }}>
            {['Technology', 'Finance', 'Healthcare', 'Marketing', 'Design', 'Education', 'Sales', 'Other'].map(v => (
              <option key={v} value={v}>{v}</option>
            ))}
          </select>
        </div>
        <div>
          <label className="label">Experience Level</label>
          <select className="input" value={form.experienceLevel} onChange={set('experienceLevel')} style={{ cursor: 'pointer' }}>
            {['Entry-level', 'Mid-level', 'Senior', 'Lead', 'Executive'].map(v => (
              <option key={v} value={v}>{v}</option>
            ))}
          </select>
        </div>
      </div>

      <div>
        <label className="label">Work Experience *</label>
        <textarea className="input textarea" rows={4}
          placeholder="Describe your work experience, roles, companies, and duration...&#10;e.g. Software Engineer at Google (2021-2024): Built scalable APIs, led team of 5..."
          value={form.experience} onChange={set('experience')} required />
      </div>

      <div>
        <label className="label">Skills *</label>
        <textarea className="input textarea" rows={3}
          placeholder="List your technical and soft skills...&#10;e.g. React, Node.js, Python, AWS, Team Leadership, Agile..."
          value={form.skills} onChange={set('skills')} required />
      </div>

      <div>
        <label className="label">Education</label>
        <textarea className="input textarea" rows={2}
          placeholder="e.g. B.S. Computer Science, MIT, 2020&#10;Relevant certifications..."
          value={form.education} onChange={set('education')} />
      </div>

      <div>
        <label className="label">Key Achievements</label>
        <textarea className="input textarea" rows={3}
          placeholder="List quantified achievements...&#10;e.g. Increased team productivity by 40%, Shipped feature used by 2M users..."
          value={form.achievements} onChange={set('achievements')} />
      </div>

      <div>
        <label className="label">Language</label>
        <select className="input" value={form.language} onChange={set('language')} style={{ cursor: 'pointer', maxWidth: '200px' }}>
          {['English', 'Spanish', 'French', 'German', 'Portuguese', 'Hindi'].map(v => (
            <option key={v} value={v}>{v}</option>
          ))}
        </select>
      </div>

      <button type="submit" className="btn btn-primary" disabled={loading}
        style={{ justifyContent: 'center', padding: '14px 28px', fontSize: '15px', alignSelf: 'flex-start' }}>
        {loading ? <><div className="spinner" />Generating Resume...</> : <><Zap size={17} />Generate Resume</>}
      </button>
    </form>
  );
};

// ─── Blog Form ────────────────────────────────────────────────────────────────
const BlogForm = ({ onSubmit, loading }) => {
  const [form, setForm] = useState({
    topic: '', tone: 'professional', audience: 'General public',
    wordCount: '800', keywords: '', outline: '', language: 'English',
  });

  const set = (field) => (e) => setForm(prev => ({ ...prev, [field]: e.target.value }));

  return (
    <form onSubmit={(e) => { e.preventDefault(); onSubmit({ ...form, wordCount: Number(form.wordCount) }); }}
      style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
      <div>
        <label className="label">Blog Topic *</label>
        <input className="input" placeholder="e.g. The Future of AI in Healthcare, 10 React Tips for 2025..."
          value={form.topic} onChange={set('topic')} required />
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '16px' }}>
        <div>
          <label className="label">Tone</label>
          <select className="input" value={form.tone} onChange={set('tone')} style={{ cursor: 'pointer' }}>
            {['professional', 'casual', 'technical', 'inspirational', 'humorous', 'educational'].map(v => (
              <option key={v} value={v}>{v.charAt(0).toUpperCase() + v.slice(1)}</option>
            ))}
          </select>
        </div>
        <div>
          <label className="label">Target Audience</label>
          <select className="input" value={form.audience} onChange={set('audience')} style={{ cursor: 'pointer' }}>
            {['General public', 'Developers', 'Business professionals', 'Students', 'Executives', 'Beginners'].map(v => (
              <option key={v} value={v}>{v}</option>
            ))}
          </select>
        </div>
        <div>
          <label className="label">Word Count</label>
          <select className="input" value={form.wordCount} onChange={set('wordCount')} style={{ cursor: 'pointer' }}>
            {['400', '600', '800', '1000', '1500', '2000'].map(v => (
              <option key={v} value={v}>{v} words</option>
            ))}
          </select>
        </div>
      </div>

      <div>
        <label className="label">SEO Keywords</label>
        <input className="input"
          placeholder="e.g. machine learning, AI tools, healthcare technology (comma-separated)"
          value={form.keywords} onChange={set('keywords')} />
      </div>

      <div>
        <label className="label">Custom Outline (Optional)</label>
        <textarea className="input textarea" rows={4}
          placeholder="Provide a custom structure or let AI decide...&#10;e.g.&#10;1. Introduction&#10;2. Current Challenges&#10;3. AI Solutions&#10;4. Future Outlook"
          value={form.outline} onChange={set('outline')} />
      </div>

      <div>
        <label className="label">Language</label>
        <select className="input" value={form.language} onChange={set('language')} style={{ cursor: 'pointer', maxWidth: '200px' }}>
          {['English', 'Spanish', 'French', 'German', 'Portuguese', 'Hindi'].map(v => (
            <option key={v} value={v}>{v}</option>
          ))}
        </select>
      </div>

      <button type="submit" className="btn btn-primary" disabled={loading}
        style={{ justifyContent: 'center', padding: '14px 28px', fontSize: '15px', alignSelf: 'flex-start' }}>
        {loading ? <><div className="spinner" />Generating Blog Post...</> : <><Zap size={17} />Generate Blog Post</>}
      </button>
    </form>
  );
};

// ─── Main GeneratePage ────────────────────────────────────────────────────────
const GeneratePage = () => {
  const { type: urlType } = useParams();
  const [selectedType, setSelectedType] = useState(urlType || null);
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();
  const { updateUser, user } = useAuth();

  const handleGenerate = async (formData) => {
    if (!selectedType) return;
    setLoading(true);
    try {
      toast.loading('AI is generating your content...', { id: 'generate' });
      const { data } = await aiAPI.generate(selectedType, formData);
      toast.success('Content generated!', { id: 'generate' });
      updateUser({ generationsUsed: (user?.generationsUsed || 0) + 1 });
      navigate(`/editor/${data.document.id}`);
    } catch (err) {
      const msg = err.response?.data?.error || 'Generation failed. Please try again.';
      toast.error(msg, { id: 'generate' });
    } finally {
      setLoading(false);
    }
  };

  if (!selectedType) {
    return <TypeSelector onSelect={setSelectedType} />;
  }

  return (
    <div className="container" style={{ paddingTop: '40px', paddingBottom: '60px', maxWidth: '780px' }}>
      {/* Header */}
      <div className="fade-in" style={{ marginBottom: '32px' }}>
        <button className="btn btn-ghost" onClick={() => setSelectedType(null)}
          style={{ marginBottom: '16px', padding: '6px 0', color: 'var(--text-muted)' }}>
          ← Back
        </button>
        <div style={{ display: 'flex', alignItems: 'center', gap: '14px' }}>
          <div style={{
            width: '44px', height: '44px',
            background: selectedType === 'resume' ? 'rgba(108,99,255,0.15)' : 'rgba(67,217,162,0.12)',
            borderRadius: '12px',
            display: 'flex', alignItems: 'center', justifyContent: 'center',
          }}>
            {selectedType === 'resume'
              ? <Briefcase size={20} color="var(--accent)" />
              : <BookOpen size={20} color="var(--accent-green)" />}
          </div>
          <div>
            <h1 style={{ fontSize: '26px', letterSpacing: '-0.03em' }}>
              Generate {selectedType === 'resume' ? 'Resume' : 'Blog Post'}
            </h1>
            <p style={{ color: 'var(--text-secondary)', fontSize: '14px', marginTop: '2px' }}>
              Fill in the details below. AI will handle the rest.
            </p>
          </div>
        </div>
      </div>

      {/* Form */}
      <div className="card fade-in fade-in-delay-1">
        {selectedType === 'resume'
          ? <ResumeForm onSubmit={handleGenerate} loading={loading} />
          : <BlogForm onSubmit={handleGenerate} loading={loading} />
        }
      </div>
    </div>
  );
};

export default GeneratePage;
